const input = $input.first().json;
const body = input.body || input;

const service_id = String(body.service_id || 'google_calendar');
const success = body.success;
const result = success ? 'success' : 'failure';
const error_message = body.error_message || null;

const SERVICE_ID_RE = /^[a-zA-Z0-9_-]{1,100}$/;
if (!SERVICE_ID_RE.test(service_id)) {
  throw new Error('Invalid service_id');
}

const safe_error = error_message
  ? String(error_message).substring(0, 500)
  : 'none';

return [{ json: { service_id, result, error_message: safe_error, metadata: body.metadata || {} } }];

const items = $input.all();

if (!items.length || !items[0].json || !items[0].json.service_id) {
  return [{ json: {
    success: false,
    error_code: 'SERVICE_NOT_FOUND',
    error_message: 'Service not initialized in circuit_breaker_state table',
    data: null,
    _meta: {
      source: 'CB_GCal_Circuit_Breaker',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id || 'unknown'
    }
  }}];
}

const state = items[0].json;

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    recorded: true,
    service_id: state.service_id,
    new_state: state.state,
    failure_count: state.failure_count,
    success_count: state.success_count
  },
  _meta: {
    source: 'CB_GCal_Circuit_Breaker',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id || 'unknown'
  }
}}];
